import React, { useEffect, useState } from 'react';
import HeapView from './components/HeapView';
import Controls from './components/Controls';

const API = 'http://localhost:5000/api';

export default function App() {
  const [heap, setHeap] = useState({ n: 0, roots: [], nodes: [], min: null });
  const [error, setError] = useState(null);

  const refresh = async () => {
    try {
      setError(null);
      const res = await fetch(`${API}/heap`);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();
      setHeap(data);
    } catch (err) {
      console.error('Failed to load heap:', err);
      setError(err.message || 'Fetch error');
      // keep previous heap state to avoid blank UI
    }
  };

  useEffect(() => { refresh(); }, []);

  return (
    <div style={{ padding: 20, fontFamily: 'Segoe UI, Roboto, Arial' }}>
      <h2>Fibonacci Heap Visualizer (no DB)</h2>
      {error && <div style={{ color: 'crimson' }}>Error: {error}</div>}
      <Controls onInsert={async (k, label) => {
        try {
          await fetch(`${API}/insert`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ key: Number(k), label }) });
        } catch (e) { console.error(e); }
        refresh();
      }} onExtract={async () => { await fetch(`${API}/extract-min`, { method: 'POST' }).catch(e => console.error(e)); refresh(); }} onClear={async () => { await fetch(`${API}/clear`, { method: 'POST' }).catch(e => console.error(e)); refresh(); }} />
      <div style={{ marginTop: 20 }}>
        <strong>Nodes:</strong> {heap.n} &nbsp; <strong>Min:</strong> {heap.min ?? '—'}
      </div>
      <HeapView data={heap} />
    </div>
  );
}
